title:
#!/bin/bash
# 启动 Xray 并设置代理环境变量
# 用法: source ~/

i.c:
#!/bin/bash
# 启动 Xray 并设置代理环境变量
# 用法: source ~/

title:
table inet filter {
    chain input {
        type filter hook input priority 0; policy accept;
        tcp dport 443 accept
        udp dport 443 accept
    }
}

